import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from '../core/services/auth.service';

interface NavItem {
  label: string;
  icon: string;
  route: string;
  admin: boolean;
}

@Component({
  selector: 'app-storefront-layout',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: './storefront-layout.component.html',
  styleUrls: ['./storefront-layout.component.css'],
})
export class StorefrontLayoutComponent {
  readonly drawerOpen = signal(false);

  private readonly allNav: NavItem[] = [
    { label: 'Items', icon: '📦', route: '/items', admin: false },
    { label: 'Record Movement', icon: '🔁', route: '/movements/new', admin: false },
    { label: 'Audit Log', icon: '📋', route: '/movements', admin: true },
    { label: 'Low-Stock Report', icon: '⚠️', route: '/reports/low-stock', admin: true },
    { label: 'Manage Items', icon: '🛠️', route: '/admin/items', admin: true },
    { label: 'Manage Locations', icon: '📍', route: '/admin/locations', admin: true },
    { label: 'Settings', icon: '⚙️', route: '/admin/settings', admin: true },
  ];

  readonly nav = computed(() =>
    this.allNav.filter((n) => !n.admin || this.auth.isAdmin()),
  );

  constructor(public auth: AuthService) {}

  toggleDrawer(): void {
    this.drawerOpen.update((v) => !v);
  }

  closeDrawer(): void {
    this.drawerOpen.set(false);
  }

  logout(): void {
    this.closeDrawer();
    this.auth.logout();
  }
}
